-----------------------------------------------------------------
---寻路行为
-----------------------------------------------------------------
---@type LFightIdleBaseAction
local LFightIdleBaseAction = LXImport(".LFightIdleBaseAction")

---@class LFightIdleGotoBossAction:LFightIdleBaseAction
local LFightIdleGotoBossAction = LxClass("LFightIdleGotoBossAction",LFightIdleBaseAction)
-----------------------------------------------------------------
local _Steps = {
	None = 0,
	Move = 1,
	MoveEnd = 2,
	Done = 99
}

function LFightIdleGotoBossAction:LFightIdleGotoBossAction()
	self._action = LFightIdleConst.ACTION_GOTOBOSS
	self._step = 0
end

-----------------------------------------------------------------
function LFightIdleGotoBossAction:OnRun(time)
	if self._step == _Steps.None or self._step == _Steps.Done then return end
	if self._step == _Steps.MoveEnd then
		self._step = _Steps.Done
		local objCtrl = self._manager:GetObjCtrl()
		objCtrl:PrepareGotoBossFinished()
		return
	end
	if self._step == _Steps.Move then
		if not self._obj:GetMoveActor():IsMoving() then
			self._step = _Steps.MoveEnd
		end
		return
	end
end
-----------------------------------------------------------------
--转换状态
function LFightIdleGotoBossAction:ResetDefaultAction()
	local ai = self._ai
	ai:ChangeAction(ai:GetDefaultAction())
end

function LFightIdleGotoBossAction:StartAction()
	local obj = self._obj
	self._obj:StopActor(true)
	local objCtrl = self._manager:GetObjCtrl()

	local nowPos = obj:GetPosition()
	local targetX = objCtrl:GetGotoBossX()

	obj:SetStatus(LFightIdleConst.STATUS_CHALLENGE)

	if nowPos.x >= targetX then
		self._step = _Steps.MoveEnd
	else
		self._step = _Steps.Move
		local speed = objCtrl:GetHeroMoveUpSpeed() * 0.01
		if speed == 0 then
			speed = 1
		end
		local dis = (targetX - nowPos.x)
		local time = dis / speed
		obj:GetMoveActor():MoveTo(Vector3(targetX, nowPos.y, 0), time)
	end
end

-----------------------------------------------------------------
function LFightIdleGotoBossAction:StopAction()

end

-----------------------------------------------------------------
function LFightIdleGotoBossAction:Destroy()
	LFightIdleBaseAction.Destroy(self)
end


return LFightIdleGotoBossAction